import React, {useEffect, useState} from 'react';
import { Modal, Card, Row, Col, Input, Select, Button } from 'antd';
import '../../../CSS/modal_dialog.css';
import deleteButton from '../../../images/deleteButton.svg';
import editButton from '../../../images/edit.svg';
import { containerConstantsService } from '../../../utils/containerconstants/ContainerConstants';
import { OPERATIONS, LOGICAL_OPERATOR, STATUS, DATA_VALIDATION, OPERATOR, OPERATOR_CONSTANT } from '../../../utils/constants';
import { PlusOutlined } from '@ant-design/icons';
import {notifyResponseMessage} from '../../commoncomponent/NotificationComponent/notifyResponseMessage';
import { fetchValidationRule } from '../../APIConfig/DataValidationAction';
import { useStore } from '../../hook-store/store';

const containerConstants = containerConstantsService.getInstance();

const ModalDialog = ( {activeTab, rules, operationType, editData, ...otherprops} ) => {
    const store = useStore(true)[0];
    const [dataChanged, setDataChanged] = useState(false);
    const [operationTypeState, setOperationTypeState] = useState(operationType);    
    const [rulesData, setRulesData] = useState(
        [
            [
                {                                      
                    
                }  
            ]
        ]
    );

    const [rulesOptions, setRulesOptions] = useState([]);    
    const [rulesOptionsMap, setRulesOptionsMap] = useState({});
    const [rulesIdOptionsMap, setRulesIdOptionsMap] = useState({});
    const [anyUpdation , setAnyUpdation] = useState(false);
    const [validationruleFormData, setValidationRulesFormData] = useState({
        'ruleName' : '',
        'condition' : '',
        'rightValue': '',
        'id':''
    });

    useEffect(() => {
        // Fetch data once when component mounts & then after tab switch.
        if (activeTab === DATA_VALIDATION.FIELDS) {
            fetchInitDataForFields();
        }
    }, [activeTab]);

    useEffect(()=>{
        if(editData !== undefined && editData !== null && Object.keys(editData).length>0){
            if( activeTab === DATA_VALIDATION.FIELDS){
                //setRulesData(editData);
                // Object.keys(rulesIdOptionsMap).length === 0 && fetchInitDataForFields();
                Object.keys(rulesIdOptionsMap).length>0 && convertToRules(editData.validations);
            }else if( activeTab === DATA_VALIDATION.VALIDATION_RULES ) {
                setValidationRulesFormData({
                    'ruleName' : editData.ruleName,
                    'condition' : editData.condition,
                    'rightValue': editData.rightValue,
                    'id': editData.id,
                });
            }
            
        }        
    },[editData, rulesIdOptionsMap, activeTab]);

    const fetchInitDataForFields = () => {
        fetchValidationRule()
            .then(response => {
                if(response.status===200 && response.data && response.data.status === 'Success' ){ 
                    let operatorIdMap = {};
                    
                    Object.keys(OPERATOR).forEach((k, i) => {
                        operatorIdMap[OPERATOR[k]]=containerConstants.formatString(containerConstants[k]);                            
                    });
                    
                    let validationRules = response.data?.data['validationsRulesDto'] ;
                    let validationRulesOptions = [{label  :containerConstants.formatString(containerConstants.SELECT), value:'' }]
                    let validationRulesOptionsMap = {};
                    let validationRulesIdOptionsMap = {};
                    validationRules !== undefined  && validationRules !== null 
                        && validationRules.length>0
                        && validationRules.forEach(item=>{
                            item.condition = operatorIdMap[item.condition];
                            validationRulesOptions.push(
                                {
                                    label: item.ruleName,
                                    value: item.ruleName,                                
                                }
                            );
                            validationRulesOptionsMap[item.ruleName]=item;
                            validationRulesIdOptionsMap[item.ruleKey] = item;
                        });

                        setRulesOptions(validationRulesOptions);
                        setRulesOptionsMap(validationRulesOptionsMap);
                        setRulesIdOptionsMap(validationRulesIdOptionsMap);
                }
            })
            .catch(error => {

                
            });
            
    }

    const convertToRules =(validations) => {
        if( validations === undefined || validations === null ){
            return ;
        }
        let rules = [...rulesData];

        var temp = '';
        var index = -1;
        var innerIndex = 0;
        var rule;
        for(var i = 0 ; i < validations.length ; i++ ){
                switch(validations.charAt(i)){
                    case '&':
                        if(i+1 < validations.length && validations.charAt(i+1) === '&' ){
                            if(temp.length>0){
                                index++;
                                rules[index]=[]; 
                                rule=rulesIdOptionsMap[temp];                    
                                rules[index][innerIndex++] = rule.ruleName;                                
                            }
                            i++;
                        }else{
                            notifyResponseMessage(STATUS.ERROR,'Invalid Rule');
                            throw '';
                        }
                        temp = '';                   
                        break;
                    case '|':
                        if(i+1 < validations.length && validations.charAt(i+1) === '|' ){
                            if (temp.length > 0) {
                                index++;
                                innerIndex = 0;
                                rules[index] = [];
                                rule = rulesIdOptionsMap[temp];
                                rules[index][innerIndex] = rule.ruleName;
                            }
                            i++;
                        }else{
                            notifyResponseMessage(STATUS.ERROR,'Invalid Rule');
                            throw '';
                        }
                        temp = '';
                        break;
                case '(':
                        if(temp.length>0){
                            rule=rulesIdOptionsMap[temp];                    
                            rules[index][innerIndex++] = rule.ruleName; 
                        }
                        temp = '';
                        break;
                case ')':
                    if(temp.length>0){
                        rule=rulesIdOptionsMap[temp];
                        rules[index][innerIndex++] = rule.ruleName;
                }
                    temp = '';
                    break;
                default:
                temp+=validations.charAt(i);
                    break;
            }
        }

        if(temp.length>0){
            rule=rulesIdOptionsMap[temp];   
            index++;
            innerIndex = 0;
            rules[index]=[];                 
            rules[index][innerIndex] = rule.ruleName;                                
        }

        setRulesData(rules);

        
    }

    const addANDValidationRowHandler = (index) => {
        let rule = [...rulesData];
        rule[index].push({
                 
        } );
        setRulesData(rule);
        setAnyUpdation(true);
        setDataChanged(!dataChanged);
    }

    const removeANDValidationRowHandler = ( index, innerIndex ) => {
        let rule = [...rulesData];
        setAnyUpdation(true);
        if( index === 0 && rule.length === 1 && rule[index] !== undefined &&  rule[index].length === 1){
            rule[index]=[{}];
            setRulesData(rule);
            setDataChanged(!dataChanged);
            // setSavebuttonEnabled(true);
            //notifyResponseMessage(STATUS.ERROR,'can not remove only row');
            return;
        }
        if( innerIndex === 0 && rule[index].length === 1 ){
            rule.splice( index, 1 );
        }else{
            rule[index].splice( innerIndex,1 );
        }
        setRulesData(rule);
        setDataChanged(!dataChanged);
    }

    const updateFormFieldValueHandler = (value, key, index, innerIndex) => {
        setAnyUpdation(true);
        // setSavebuttonEnabled(true);
        let rule = [...rulesData];
               
        rule[index][innerIndex] = value;
        setRulesData(rule);
        setDataChanged(!dataChanged);        
    }

    const updateValidationFormValueHandler = (value,key, event) => {
        // setSavebuttonEnabled(true);
        setAnyUpdation(true);
        if(key === 'rightValue' && !isNumberKeyOnly(event)){
            return;
        }

        let rule = {...validationruleFormData};        
        rule[key] = value;
        if(key === 'condition'){
            rule['rightValue']='';
        }
        setValidationRulesFormData(rule);
        setDataChanged(!dataChanged);        
    }

    const isNumberKeyOnly = (event)=> {

        if( validationruleFormData['condition'] === OPERATOR.LESS_THAN 
            || validationruleFormData['condition'] === OPERATOR.GREATER_THAN
            || validationruleFormData['condition'] === OPERATOR.GREATER_THAN_EQUALS
            || validationruleFormData['condition'] === OPERATOR.LESS_THAN_EQUALS )
        {            
            if (isNaN(event.target.value)) {
                const lst = String(event.target.value).slice(-1);
                if(lst ==="-" || lst ===":" || !isNaN(lst)){
                    return true;
                }
                event.preventDefault();
                return false;
              }
                
        }
        return true;
    }

    
    const addORValidationHandler = () => {
        let rule = [...rulesData];
        rule.push([{            
            
        } ]);
        setRulesData(rule);
        setAnyUpdation(true);
        setDataChanged(!dataChanged);
    }
    
    const getRuleFormula = () => {
        let finalFormula = '';
        rulesData.map(function(item, index){                       
            let c =''; 
            item.map(function(innerItem, innerIndex){
                if( innerItem !== undefined && innerItem !== '' && Object.keys(innerItem).length>0 ){
                    c = c + ' ' + innerItem + ' &&' ;
                }
                
            })

            if(c.length>3){
                c = c.substring(1,c.length-3);
                if(c.indexOf('&&')>-1){
                    finalFormula = finalFormula + ' (' + c + ') ||';
                }else{
                    finalFormula = finalFormula + ' ' + c +' ||';
                }
            }
        });
        if(finalFormula.length>3){
            finalFormula = finalFormula.substring(0,finalFormula.length-3);
        }

        return finalFormula;
    }

    const getRuleFormulaToSave = () => {
        let finalFormula = '';
        rulesData.map(function(item, index){                       
            let c =''; 
            item.map(function(innerItem, innerIndex){
                if( innerItem !== undefined && innerItem !== '' && Object.keys(innerItem).length>0 && rulesOptionsMap[innerItem] ){
                    c = c + rulesOptionsMap[innerItem].ruleKey + '&&' ;
                }
                
            })

            if(c.length>2){
                c = c.substring(0,c.length-2);
                if(c.indexOf('&&')>-1){
                    finalFormula = finalFormula + '(' + c + ')||';
                }else{
                    finalFormula = finalFormula + c +'||';
                }
            }
        });
        if(finalFormula.length>2){
            finalFormula = finalFormula.substring(0,finalFormula.length-2);
        }

        return finalFormula;
    }

    const calculateRulesCount = () => {
        let count = 0;
        rulesData.map(function(item, index){                       
             
            item.map(function(innerItem, innerIndex){
                if( innerItem !== undefined && innerItem !== '' &&  Object.keys(innerItem).length>0 ){
                    count++;
                }
                
            })
        })
        return count;
    }

    const getDivider = (type) => {
        return <div style ={{flexDirection: 'row', display: 'flex', margin: '16px 0px'}}>
            <div style ={{width: '50%',borderTop: '1px solid #DADADA', transform: 'translateY(50%)'}}></div>
            <div className='font-family-weight-500 fs9 ls12'
                style = {{ background: '#E5F6FF', width: '30px', border: '1px solid #BAE6FF', boxSizing: 'border-box', borderRadius: '30px', justifyContent: 'center', alignItems: 'center', display: 'flex' }}
            >
                {type}
            </div>
            <div style ={{width: '50%',borderTop: '1px solid #DADADA', transform: 'translateY(50%)'}}></div>
        </div>
    }

    const getRulesOptions = (innerIndex,index) => {
        const rulesDataSet = new Set();
        let finalRulesOptions = []

        rulesData[index].map(function(item, index1){
            rulesDataSet.add(item);

        });

        for(let rule of rulesOptions){
            if(! rulesDataSet.has(rule.value) ){
                finalRulesOptions.push(rule)
            }
        };
        return finalRulesOptions;
    }

    const displayFieldDataform = (type, data, index, innerIndex) => {

        return  <div id ={index}>
            { innerIndex > 0 && getDivider(LOGICAL_OPERATOR.AND) }
            <Row style ={{ flexDirection: 'row', display: 'flex'}}>
                <Col style={ {  width: operationTypeState !== OPERATIONS.SHOW ?  '30%' : '32%',  marginRight : '2%', flexDirection: 'column'} }>                    
                    <div className = 'font-family-weight-500 fs12 ls18 ' style ={{color: '#727272', marginBottom: '2px'}} >{containerConstants.formatString(containerConstants.RULE_NAME)}</div>
                    
                    <Select      
                        value = {Object.keys(rulesData[index][innerIndex]).length >0 ? rulesData[index][innerIndex] : null}
                        showSearch = {false}
                        size = 'default'
                        style={{ width: '100%' }}                        
                        onChange = {(event) => updateFormFieldValueHandler(event, 'ruleName', index, innerIndex)}                        
                        placeholder={containerConstants.formatString(containerConstants.SELECT)}
                        options={getRulesOptions(innerIndex,index)}
                        disabled = {operationTypeState === OPERATIONS.SHOW}
                    >
                    </Select>
                </Col>
                <Col style={ { width: operationTypeState !== OPERATIONS.SHOW ?  '30%' : '32%', marginRight : operationTypeState !== OPERATIONS.SHOW ? '3%' : '2%', flexDirection: 'column'} }>
                    <div className = 'font-family-weight-500 fs12 ls18 ' style ={{color: '#727272', marginBottom: '2px'}} >{containerConstants.formatString(containerConstants.OPERATOR)}</div>                     
                    <Input disabled = {true} className= 'font-family-weight-normal fs14 ls22 input-box-style' style = {{background: '#F3F3F3'}} value = {rulesOptionsMap[rulesData[index][innerIndex]] !==undefined ? rulesOptionsMap[rulesData[index][innerIndex]].condition : ''} />
                </Col>
                <Col style={{  width: operationTypeState !== OPERATIONS.SHOW ?  '30%' : '32%', marginRight: operationTypeState !== OPERATIONS.SHOW ? '2%' : '0px',flexDirection: 'column'} }>
                    <div className = 'font-family-weight-500 fs12 ls18 ' style ={{color: '#727272', marginBottom: '2px'}} >{containerConstants.formatString(containerConstants.RIGHT_VALUE)}</div>
                    <Input disabled = {true} className= 'font-family-weight-normal fs14 ls22 input-box-style' style = {{background: '#F3F3F3'}} value = {rulesOptionsMap[rulesData[index][innerIndex]] !==undefined ? rulesOptionsMap[rulesData[index][innerIndex]].rightValue : ''} />
                </Col>
                { operationTypeState !== OPERATIONS.SHOW && <Col style={ { width: '3%'} }>
                        <div className = 'font-family-weight-500 fs12 ls18 ' style ={{color: '#727272', marginBottom: '2px', visibility: 'hidden'}} >.</div>
                        <img src={deleteButton} alt="Imgage not found" onClick={()=>removeANDValidationRowHandler( index, innerIndex )}
                            style={{ cursor:'pointer'}}/>
                    </Col>
                }
            </Row>
        </div>
    }

    const isRightInputDisabled = () => {
        if( validationruleFormData['condition'] === OPERATOR.REQUIRED 
            || validationruleFormData['condition'] === OPERATOR.NOT_NULL ){
        
                validationruleFormData['rightValue']='';
                return true;
        }
        
        return false;
    }

    const calculateEmptyRulesCountExceptExceptionalCase = () => {

        let emptycount = 0;
        let ruleCount = 0;
        let indexVal = -1;
        rulesData.map(function(item, index){
            item.map(function(innerItem, innerIndex){
                if( innerItem === undefined || innerItem === '' ||  Object.keys(innerItem).length === 0 ){
                    emptycount++;
                    indexVal = index+"_"+innerIndex;
                }else{
                    ruleCount++;
                }
            })
        })
        if(emptycount === 1 && ruleCount === 0){
            let v = indexVal.split('_');
            return v[0] === '0' && v[1] === '0' ? 0 : 1;
        }

        if(ruleCount > 0 && emptycount > 0){
            return 1;
        }
        return emptycount;
    }

    const isAddButtonDisabled = () => {
        
        if( anyUpdation && activeTab === DATA_VALIDATION.FIELDS ){
            return calculateEmptyRulesCountExceptExceptionalCase() > 0;
        }else if( anyUpdation && activeTab === DATA_VALIDATION.VALIDATION_RULES ) {
            return validationruleFormData['ruleName'] === '' 
                || validationruleFormData['condition'] === ''
                || validationruleFormData['ruleName'].trim() === ''
                ||( validationruleFormData['condition'] !== OPERATOR.REQUIRED
                    && validationruleFormData['condition'] !== OPERATOR.NOT_NULL
                        && (validationruleFormData['rightValue'] ===''
                                || validationruleFormData['rightValue'].trim() ==='')
                    )

        }
        
        return true;
            
    }

    const displayValidationDataForm = () => {
        return  <div>
           
            <Row style ={{ flexDirection: 'row', display: 'flex'}}>
                <Col style={ { width: '32%',  marginRight : '2%', flexDirection: 'column'} }>
                    <div className = 'font-family-weight-500 fs12 ls18 ' style ={{color: '#727272', marginBottom: '2px'}} >{containerConstants.formatString(containerConstants.RULE_NAME)}</div>
                    <Input placeholder={containerConstants.formatString(containerConstants.PLACEHOLDER)} className= 'input-box-style' value = {validationruleFormData['ruleName']} onChange = {event => updateValidationFormValueHandler( event.target.value, 'ruleName' )} onBlur = {event => updateValidationFormValueHandler( event.target.value, 'ruleName' )}/>
                </Col>
                <Col style={ { width: '32%', marginRight : '2%',flexDirection: 'column'} }>
                    <div className = 'font-family-weight-500 fs12 ls18 ' style ={{color: '#727272', marginBottom: '2px'}} >{containerConstants.formatString(containerConstants.OPERATOR)}</div>
                    <Select      
                        value = {validationruleFormData['condition']}
                        onChange = {(event) => updateValidationFormValueHandler(event, 'condition')}
                        size = 'default'                         
                        style = {{height: '30px', width: '100%', background: '#FFFFFF', border: '1px solid #C9C9C9',boxSizing: 'border-box', borderRadius: '2px'}}                    
                        options= {OPERATOR_CONSTANT}                         
                    >
                    </Select>
                </Col>
                <Col style={ { width: '31%',flexDirection: 'column'} }>
                    <div className = 'font-family-weight-500 fs12 ls18 ' style ={{color: '#727272', marginBottom: '2px'}} >{containerConstants.formatString(containerConstants.RIGHT_VALUE)}</div>
                    <Input placeholder={containerConstants.formatString(containerConstants.PLACEHOLDER)} className= 'input-box-style' value = {validationruleFormData['rightValue']} onChange = {event => updateValidationFormValueHandler( event.target.value, 'rightValue' ,event)} onBlur = {event => updateValidationFormValueHandler( event.target.value, 'rightValue', event )} disabled = {isRightInputDisabled()} />
                </Col>

            </Row>
        </div>
    }

    const displayAddAnotherConditionButton = () => {
        return  <Button 
                    style={{ border: '1px solid', boxSizing: 'border-box', borderRadius : '2px', alignItems: 'center', display: 'flex', marginTop: '13px'}} 
                    type="primary"
                    onClick={()=>addORValidationHandler()}
                    ghost
                >
                    <PlusOutlined size = '9px' style = {{marginRight: '7px'}}/>
                    <div className='font-family-weight-normal fs14 ls22' >{containerConstants.formatString(containerConstants.ADD_ANOTHER_CONDITION)}</div>
                </Button>
    }
    

    const displayFormula = () => {
        return  <Input className= 'rule-output-box font-family-weight-500 fs14 ls22 ' value = {containerConstants.formatString(containerConstants.FORMULA)+ getRuleFormula()} />

    }

    const editRule = () => {
        setOperationTypeState(OPERATIONS.EDIT);
    }

    return(        
        <Modal
            className = 'ModalStyles'
            title= {<div style ={{ flexDirection: 'row', display: 'contents' }}>
                    <div style = {{display: 'contents'}} >{
                        operationTypeState === OPERATIONS.SHOW ? 
                        (editData ? editData.fields : '') + " " + containerConstants.formatString(containerConstants.VALIDATION) 
                            : 
                            operationTypeState === OPERATIONS.ADD ?
                                containerConstants.formatString(containerConstants.ADD) + " " + containerConstants.formatString(containerConstants.VALIDATION)
                                :
                                operationTypeState === OPERATIONS.EDIT_VALIDATION ?
                                containerConstants.formatString(containerConstants.EDIT) + " " + containerConstants.formatString(containerConstants.VALIDATION)
                                :
                                containerConstants.formatString(containerConstants.EDIT) + " " + editData.fields +" "+ containerConstants.formatString(containerConstants.VALIDATION)
                        }
                    </div>
                    { operationTypeState === OPERATIONS.SHOW && <div style = {{float: 'right'}}>                    
                            <img 
                                className = { store.fromFCR ? '' : store.showCustom  ? 'non_selectable' : '' }
                                src={editButton}
                                alt="Imgage not found" 
                                onClick={()=> ( store.fromFCR || ! store.showCustom ) && editRule()}
                                style={{ cursor:'pointer'}}
                            />
                        </div>
                    }
                </div>
            }

            centered
            bodyStyle= {{padding: '16px',
                fontSize: '14px',
                lineHeight: '1.5',
                wordWrap: 'break-word'}}
            closable = {false}
            visible={true}
            width = {'60%'}
            okText = 'Add'
            footer={[
                <div style = {{ flexDirection: 'row', display: 'flex', justifyContent: 'end', marginTop: '14px' }} >
                    { operationTypeState !== OPERATIONS.SHOW && <Button
                            id= 'cancel_botton_style'
                            className = 'font-family-weight-500 fs14 ls22'
                            onClick={()=>otherprops.closeAddFieldValidationForm(false)}
                        >
                            {containerConstants.formatString(containerConstants.CANCEL)}
                        </Button>                    
                    }
                    { operationTypeState === OPERATIONS.SHOW &&  <Button
                            type="primary"
                            onClick={()=>otherprops.closeAddFieldValidationForm(false)}
                            className = 'ont-family-weight-500 fs14 ls22'
                            style = {{ color: '#FFFFFF', textAlign: 'center', marginBottom: '14px' }}
                        >
                            {containerConstants.formatString(containerConstants.CLOSE)}
                        </Button>
                    }
                    { operationTypeState !== OPERATIONS.SHOW &&  <Button
                            type="primary"
                            loading={otherprops.showLoading}
                            onClick={()=>otherprops.saveValidationForm( activeTab === DATA_VALIDATION.FIELDS ? {'rulesData':getRuleFormulaToSave(),'rulesCount':calculateRulesCount(), 'attributeId':editData.attributeId,'attributeValidationId':editData.attributeValidationId, 'operationType': operationTypeState} : {'rulesData':validationruleFormData} )}
                            className = 'ont-family-weight-500 fs14 ls22'
                            style = {{ color: '#FFFFFF', textAlign: 'center', marginBottom: '14px' }}
                            disabled = {isAddButtonDisabled()}
                        >
                            {operationTypeState === OPERATIONS.EDIT || operationTypeState === OPERATIONS.EDIT_VALIDATION ? containerConstants.formatString(containerConstants.SAVE) : containerConstants.formatString(containerConstants.ADD)}
                        </Button>
                    }
                </div>
              ]}
            onCancel={() => otherprops.closeAddFieldValidationForm(false)}
            >
            {        
            
                activeTab === DATA_VALIDATION.FIELDS && rulesData.map(function(item, index){                        
                    return <>
                    
                        { index > 0 &&getDivider(LOGICAL_OPERATOR.OR) }   
                        
                        <Card 
                            bodyStyle = {{padding : '16px 16px'}}
                            className='Modal-content-layout'                
                        >                                           
                            { 
                                item.map(function(innerItem, innerIndex){
                                    return displayFieldDataform(LOGICAL_OPERATOR.AND,innerItem,index,innerIndex);
                                })
                            }
                        
                            { operationTypeState !== OPERATIONS.SHOW && <Button 
                                    style={{ border: '1px solid', boxSizing: 'border-box', borderRadius : '2px', alignItems: 'center', display: 'flex', marginTop: '13px'}} 
                                    type="primary"
                                    onClick={()=>addANDValidationRowHandler(index)}
                                    ghost
                                >
                                    <div className='font-family-weight-normal fs14 ls22' >{LOGICAL_OPERATOR.AND}</div>
                                </Button> 
                            }
                        </Card>
                    </>   
                })
            }            
            { operationTypeState !== OPERATIONS.SHOW && activeTab === DATA_VALIDATION.FIELDS && displayAddAnotherConditionButton() }
            { activeTab === DATA_VALIDATION.FIELDS && displayFormula() }
            { activeTab === DATA_VALIDATION.VALIDATION_RULES && displayValidationDataForm() }
            
        </Modal>        
    );
}
export default ModalDialog;
